function f(e){if(!e)return"";const o=Date.now()-new Date(e).getTime(),t=Math.floor(o/6e4);if(t<1)return"just now";if(t<60)return`${t}m ago`;const r=Math.floor(t/60);if(r<24)return`${r}h ago`;const a=Math.floor(r/24);return a<7?`${a}d ago`:`${Math.floor(a/7)}w ago`}function i(e){return e?new Date(e).toLocaleDateString("en-US",{month:"short",day:"numeric",year:"numeric"}):""}function s(e){return e?Math.floor((Date.now()-new Date(e).getTime())/864e5):0}let n=null;function c(e){return e?e.includes("&")?(n||(n=document.createElement("textarea")),n.innerHTML=e,n.value):e:""}export{i as a,c as b,s as d,f};
